// IOrderQueue.cs + OrderQueue.cs
public interface IOrderQueue
{
    ValueTask QueueOrderAsync(int orderId, CancellationToken ct = default);
}

public class OrderQueue : IOrderQueue
{
    private readonly Channel<int> _channel;
    public OrderQueue(Channel<int> channel) => _channel = channel;

    public async ValueTask QueueOrderAsync(int orderId, CancellationToken ct = default)
        => await _channel.Writer.WriteAsync(orderId, ct);
}

public class BackgroundOrderProcessor : BackgroundService
{
    private readonly IServiceProvider _sp;
    private readonly ILogger<BackgroundOrderProcessor> _logger;
    private readonly Channel<int> _channel;

    public BackgroundOrderProcessor(
        IServiceProvider sp,
        ILogger<BackgroundOrderProcessor> logger,
        Channel<int> channel)
    {
        _sp = sp;
        _logger = logger;
        _channel = channel;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        await foreach (var orderId in _channel.Reader.ReadAllAsync(stoppingToken))
        {
            try
            {
                using var scope = _sp.CreateScope();
                var svc = scope.ServiceProvider.GetRequiredService<IOrderService>();
                await svc.ProcessAsync(orderId, stoppingToken);
                _logger.LogInformation("Order {OrderId} processed", orderId);
            }
            catch (OperationCanceledException) when (stoppingToken.IsCancellationRequested)
            {
                throw;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Order {OrderId} failed", orderId);
            }
        }
    }
}
